<span class="line"><span style="color:#ABB2BF;">    </span><span style="color:#C678DD;">int</span><span style="color:#ABB2BF;"> res </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> (</span><span style="color:#C678DD;">~</span><span style="color:#ABB2BF;">(x </span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;"> y)) </span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;"> (</span><span style="color:#C678DD;">~</span><span style="color:#ABB2BF;">((</span><span style="color:#C678DD;">~</span><span style="color:#ABB2BF;">x) </span><span style="color:#C678DD;">&amp;</span><span style="color:#ABB2BF;"> (</span><span style="color:#C678DD;">~</span><span style="color:#ABB2BF;">y)));</span></span>
